struct Config { key: String, value: String }

pub fn parse_config(line: &str) -> Result<Config, String> {
    let parts: Vec<&str> = line.splitn(2, '=').collect();
    if parts.len() != 2 { return Err(format!("malformed config: '{}'", line)); }
    let key = parts[0].trim().to_string();
    let value = parts[1].trim().to_string();
    if key.is_empty() { Err("empty key".into()) }
    else { Ok(Config { key, value }) }
}

