enum AppError { NotFound(String), ParseFailed(String), InvalidInput(String) }

impl AppError {
    pub fn message(&self) -> &str {
        match self { AppError::NotFound(m) | AppError::ParseFailed(m) | AppError::InvalidInput(m) => m }
    }
}

pub fn process_record(raw: &str) -> Result<u64, AppError> {
    let trimmed = raw.trim();
    if trimmed.is_empty() { return Err(AppError::InvalidInput("empty input".into())); }
    let parts: Vec<&str> = trimmed.split(':').collect();
    if parts.len() < 2 { return Err(AppError::ParseFailed("expected key:value".into())); }
    let value: u64 = parts[1].trim().parse()
        .map_err(|e| AppError::ParseFailed(format!("bad number: {}", e)))?;
    if value == 0 { Err(AppError::NotFound("zero value".into())) }
    else { Ok(value) }
}

