pub fn collect_results(items: &[Result<i32, String>]) -> Result<Vec<i32>, String> {
    let mut collected = Vec::new();
    for item in items {
        match item {
            Ok(val) => collected.push(*val),
            Err(err) => return Err(err.clone()),
        }
    }
    Ok(collected)
}

pub fn try_parse_all(strings: &[String]) -> Result<Vec<i32>, String> {
    let results: Vec<Result<i32, String>> = strings.iter()
        .map(|s| s.parse::<i32>().map_err(|e| format!("parse error: {}", e)))
        .collect();
    collect_results(&results)
}

