use std::collections::HashMap;

pub fn find_user<'a>(id: u32, db: &'a HashMap<u32, String>) -> Option<&'a String> { db.get(&id) }
pub fn find_email<'a>(name: &str, emails: &'a HashMap<String, String>) -> Option<&'a String> { emails.get(name) }

pub fn lookup_email(id: u32, users: &HashMap<u32, String>, emails: &HashMap<String, String>) -> String {
    find_user(id, users)
        .and_then(|name| find_email(name, emails))
        .map(|email| email.clone())
        .unwrap_or_else(|| "not found".to_string())
}

pub fn first_positive(values: &[i32]) -> Option<i32> {
    for val in values { if *val > 0 { return Some(*val); } }
    None
}
